import React from "react";
import { CreditCard, Plus } from "lucide-react";

export default function HomeScreen({
  balance,
  onDeposit,
  onWithdraw,
  onHistory,
}) {
  return (
    <div className="min-h-screen bg-[#f4f6fb] px-5 pt-6 pb-24">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <h1 className="text-xl font-semibold text-gray-900">
          My Account
        </h1>
        <Plus className="w-6 h-6 text-gray-700" />
      </div>

      {/* Balance Card */}
      <div className="bg-white rounded-2xl p-6 shadow-sm mb-6">
        <p className="text-sm text-gray-500">Current Balance</p>
        <p className="text-2xl font-semibold text-gray-900 mt-2">
          ₦{balance.toLocaleString()}
        </p>
      </div>

      {/* Actions */}
      <div className="space-y-4">
        <button
          onClick={onDeposit}
          className="w-full bg-emerald-600 text-white py-4 rounded-xl font-semibold active:scale-[0.98] transition flex items-center justify-center gap-2"
        >
          <CreditCard className="w-5 h-5" />
          Deposit
        </button>

        <button
          onClick={onWithdraw}
          className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition flex items-center justify-center gap-2"
        >
          <CreditCard className="w-5 h-5" />
          Withdraw
        </button>

        <button
          onClick={onHistory}
          className="w-full bg-white border border-gray-300 py-4 rounded-xl font-semibold text-gray-900 active:scale-[0.98] transition flex items-center justify-center gap-2"
        >
          Transaction History
        </button>
      </div>
    </div>
  );
}
